css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #0a0800; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 76px; border-bottom: 1px solid rgba(234,179,8,0.15); }
.logo { font-size: 22px; font-weight: 900; color: #eab308; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; }
.nav-right { display: flex; gap: 10px; }
.login { padding: 10px 20px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.12); background: transparent; color: white; font-weight: 600; cursor: pointer; }
.signup { padding: 10px 20px; border-radius: 10px; border: none; background: #eab308; color: #0a0800; font-weight: 800; cursor: pointer; }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; padding: 80px 72px; min-height: calc(100vh - 76px); }
.badge { display: inline-block; padding: 8px 16px; border-radius: 20px; background: rgba(234,179,8,0.1); border: 1px solid rgba(234,179,8,0.3); color: #eab308; font-size: 13px; font-weight: 700; margin-bottom: 24px; }
h1 { font-size: 64px; font-weight: 900; line-height: 1.05; letter-spacing: -2px; margin-bottom: 20px; } h1 span { color: #eab308; }
.hero-left p { color: #6b7280; font-size: 17px; line-height: 1.7; margin-bottom: 32px; max-width: 460px; }
.hero-actions { display: flex; gap: 14px; margin-bottom: 24px; }
.btn-main { padding: 16px 32px; border-radius: 14px; border: none; background: linear-gradient(135deg, #eab308, #f59e0b); color: #0a0800; font-weight: 800; font-size: 15px; cursor: pointer; }
.btn-ghost { padding: 16px 28px; border-radius: 14px; border: 1px solid rgba(255,255,255,0.15); background: transparent; color: white; font-weight: 600; font-size: 15px; cursor: pointer; }
.security-badges { display: flex; gap: 16px; } .security-badges span { color: #6b7280; font-size: 13px; font-weight: 500; }
.market-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(234,179,8,0.2); border-radius: 24px; padding: 24px; }
.mc-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; font-size: 14px; font-weight: 600; }
.live { color: #22c55e; font-size: 12px; }
.coin-list { display: flex; flex-direction: column; gap: 12px; margin-bottom: 20px; }
.coin-item { display: flex; align-items: center; gap: 12px; padding: 12px; border-radius: 12px; background: rgba(255,255,255,0.03); transition: background 0.2s; } .coin-item:hover { background: rgba(255,255,255,0.06); }
.coin-icon { font-size: 24px; width: 40px; text-align: center; }
.coin-name { flex: 1; } .coin-name strong { display: block; font-size: 14px; } .coin-name small { color: #6b7280; font-size: 12px; }
.coin-price { text-align: right; } .coin-price strong { display: block; font-size: 14px; font-weight: 700; } .coin-price .up { color: #22c55e; font-size: 12px; } .coin-price .down { color: #ef4444; font-size: 12px; }
.mc-footer { border-top: 1px solid rgba(255,255,255,0.06); padding-top: 16px; }
.portfolio-mini span:first-child { display: block; font-size: 12px; color: #6b7280; margin-bottom: 4px; }
.portfolio-mini strong { display: block; font-size: 24px; font-weight: 800; margin-bottom: 2px; }
.pct-up { color: #22c55e; font-size: 13px; font-weight: 700; }
.features { border-top: 1px solid rgba(255,255,255,0.07); padding: 48px 72px; }
.f-row { display: flex; justify-content: space-around; }
.f-item { text-align: center; } .f-num { font-size: 42px; font-weight: 900; color: #eab308; } .f-label { color: #6b7280; font-size: 14px; margin-top: 4px; }

js:
const coins = [
  { icon: '₿', name: 'Bitcoin', symbol: 'BTC', price: '₺1.842.500', change: '+2.4%', up: true },
  { icon: '⬡', name: 'Ethereum', symbol: 'ETH', price: '₺98.400', change: '+1.8%', up: true },
  { icon: '◎', name: 'Solana', symbol: 'SOL', price: '₺4.820', change: '-0.9%', up: false },
  { icon: '●', name: 'Cardano', symbol: 'ADA', price: '₺18.40', change: '+3.2%', up: true },
  { icon: '▲', name: 'Avalanche', symbol: 'AVAX', price: '₺1.240', change: '-1.5%', up: false }
];
document.getElementById('coin-list').innerHTML = coins.map(c => `
  <div class="coin-item">
    <div class="coin-icon">${c.icon}</div>
    <div class="coin-name"><strong>${c.name}</strong><small>${c.symbol}</small></div>
    <div class="coin-price"><strong>${c.price}</strong><span class="${c.up ? 'up' : 'down'}">${c.change}</span></div>
  </div>
`).join('');
setInterval(() => {
  document.querySelectorAll('.coin-price strong').forEach(el => {
    el.style.opacity = '0.5';
    setTimeout(() => el.style.opacity = '1', 500);
  });
}, 3000);
